#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_NUMBERS 1000

int main() {
    int numbers[MAX_NUMBERS];
    int unique[MAX_NUMBERS];
    int counts[MAX_NUMBERS] = {0};
    int n = 0;
    int unique_count = 0;
    int max_count = 0;

    char input[1000];
    fgets(input, sizeof(input), stdin);

    char *token = strtok(input, " ");
    while (token != NULL && n < MAX_NUMBERS) {
        numbers[n++] = atoi(token);
        token = strtok(NULL, " ");
    }

    for (int i = 0; i < n; i++) {
        int found = 0;
        for (int j = 0; j < unique_count; j++) {
            if (unique[j] == numbers[i]) {
                found = 1;
                break;
            }
        }
        if (!found) {
            unique[unique_count++] = numbers[i];
        }
    }

    for (int i = 0; i < unique_count; i++) {
        int count = 0;
        for (int j = 0; j < n; j++) {
            if (numbers[j] == unique[i]) {
                count++;
            }
        }
        counts[i] = count;
        if (count > max_count) {
            max_count = count;
        }
    }

    if (max_count < 4) {
        printf("Alien\n");
    } else if (max_count == 5 || unique_count == 3) {
        printf("Bear\n");
    } else {
        printf("Elephant\n");
    }

    return 0;
}
